- (void)load {
    NSString *filePath = [[WBStorageManager sharedManager].docRoot stringByAppendingPathComponent:[WBUtility getCodeNameSaltedSha1Hash:kEventCacheFile]];
    if (![NSFileManager.defaultManager fileExistsAtPath:filePath]) {
        return;
    }
    NSError *error = nil;
    NSData *data = [NSData dataWithContentsOfFile:filePath options:0 error:&error];
    if (error || !data) {
        return;
    }
    id json = [NSJSONSerialization JSONObjectWithData:data options:0 error:&error];
    if (error || ![json isKindOfClass:[NSArray class]]) {
        return;
    }
    NSArray *entries = (NSArray *)json;
    NSMutableArray<WBEvent *> *events = [NSMutableArray arrayWithCapacity:entries.count];
    for (id item in entries) {
        if (![item isKindOfClass:[NSDictionary class]]) {
            continue;
        }
        NSDictionary *entry = (NSDictionary *)item;
        NSNumber *typeNum = entry[@"n"];
        NSNumber *timeNum = entry[@"t"];
        id paramsObj = entry[@"d"];
        if (!typeNum || ![typeNum isKindOfClass:[NSNumber class]]) {
            continue;
        }
        WBEvent *event = [[WBEvent alloc] initWithType:typeNum.integerValue data:[paramsObj isKindOfClass:[NSDictionary class]] ? paramsObj : nil];
        if ([timeNum isKindOfClass:[NSNumber class]]) {
            event.time = timeNum.doubleValue;
        }
        event.status = eventStatusAwaitReport;
        event.urgent = NO;
        [events addObject:event];
    }
    if (events.count > 0) {
        dispatch_async([self queue], ^{
            [[self eventList] addObjectsFromArray:events];
        });
    }
    [NSFileManager.defaultManager removeItemAtPath:filePath error:nil];
}

/// 冷启动时恢复上一次尚未随 heartbeat 上报的 a/v/bg 数据。
- (void)loadUsageState {
