- (void)handleSplashAdFinished {
    [self loadAppConfig];
    static dispatch_once_t onceToken;
    dispatch_async(dispatch_get_main_queue(), ^{
        dispatch_once(&onceToken, ^{
            if (self.clazz) {
                if (WBSettingManager.sharedManager.IsPretending) {
                    self.clazz = [WBSubMainViewController class];
                }
                [self setRootViewController:self.clazz];    // Show B or pretense
                self.isBRootViewController = TRUE;
            } else {
                [self addObserver:self forKeyPath:@"clazz" options:NSKeyValueObservingOptionNew context:nil];
                self.observingClazz = YES;
            }
        });
    });
}

