   760	/// 热启动回前台时，先补算后台挂起区间，再判断是否需要立刻发 heartbeat。
   761	+ (void)syncUsageOnAppEnterForeground {
   762	    WBEventManager *manager = [WBEventManager defaultManager];
   763	    CFAbsoluteTime now = CFAbsoluteTimeGetCurrent();
   764	    dispatch_sync(manager.queue, ^{
   765	        // 先把后台挂起区间补算回来，再决定是否已经达到 heartbeat 阈值。
   766	        [manager applyBackgroundUsageAtTime:now];
   767	        [manager persistUsageState];
   768	        [manager reportHeartbeatIfNeeded];
   769	    });
   770	}
