   782	/// 进入后台时先结算前台区间，再记录后台时间快照，供后续热启动或终止时补算。
   783	+ (void)onAppEnterBackground {
   784	    WBEventManager *manager = [WBEventManager defaultManager];
   785	    CFAbsoluteTime now = CFAbsoluteTimeGetCurrent();
   786	    NSInteger currentVappId = [manager currentRunningVappId];
   787	    dispatch_sync(manager.queue, ^{
   788	        // 先落掉进入后台前的前台时长，再保存后台快照，后续按时间差补算。
   789	        [manager accumulateElapsedUsageAtTime:now];
   790	        [manager persistUsageState];
   791	        [WBEventManager saveBackgroundTrackingAtTime:now runningVapp:(currentVappId > 0) vappId:currentVappId];
   792	    });
   793	    // 旧逻辑：
   794	    // [WBEventManager addEventWithType:eventTypeAppEnterBackground];
   795	    // [[WBEventManager defaultManager] saveAsync];
   796	    [WBEventManager addEventWithType:eventTypeAppEnterBackground];
   797	    [manager saveAsync];
   798	    dispatch_async(dispatch_get_main_queue(), ^{
   799	        [[WBActionRequestManager sharedManager] requestReportEventWithType:WBActionRequestEventTypeAppEnterBackground defaultHandler:nil];
   800	    });
   801	}
