   803	/// 进程结束前保存最后一个可观测区间，让下一次冷启动还能继续累计同一轮 heartbeat。
   804	+ (void)onAppWillTerminate {
   805	    WBEventManager *manager = [WBEventManager defaultManager];
   806	    CFAbsoluteTime now = CFAbsoluteTimeGetCurrent();
   807	    dispatch_sync(manager.queue, ^{
   808	        // 保存进程结束前最后一段可观测时长，保证下次冷启动还能续上这轮 heartbeat。
   809	        if ([WBEventManager hasBackgroundEnterTime]) {
   810	            [manager applyBackgroundUsageAtTime:now];
   811	        } else {
   812	            [manager accumulateElapsedUsageAtTime:now];
   813	        }
   814	        [manager persistUsageState];
   815	    });
   816	    // 旧逻辑：
   817	    // [[WBEventManager defaultManager] save];
   818	    [manager save];
   819	}
